package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertInstanceOf;
import static org.junit.jupiter.api.Assertions.assertNull;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.Map;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.Compare;
import org.eclipse.rdf4j.query.algebra.Extension;
import org.eclipse.rdf4j.query.algebra.ExtensionElem;
import org.eclipse.rdf4j.query.algebra.LeftJoin;
import org.eclipse.rdf4j.query.algebra.QueryRoot;
import org.eclipse.rdf4j.query.algebra.Service;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.impl.EvaluationStatistics;
import org.eclipse.rdf4j.query.impl.EmptyBindingSet;
import org.junit.jupiter.api.Test;

class LmdbOptionalNormalFormOptimizerTest {

	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void normalizesIndependentWellDesignedOptionals() {
		StatementPattern base = statementPattern("person", "type", "type");
		StatementPattern zBranch = statementPattern("person", "zProp", "zValue");
		StatementPattern aBranch = statementPattern("person", "aProp", "aValue");
		QueryRoot root = new QueryRoot(new LeftJoin(new LeftJoin(base, zBranch), aBranch));

		optimize(root);

		LeftJoin top = assertInstanceOf(LeftJoin.class, root.getArg(), () -> root.toString());
		LeftJoin inner = assertInstanceOf(LeftJoin.class, top.getLeftArg(), () -> root.toString());
		assertObjectVar(inner.getRightArg(), "aValue");
		assertObjectVar(top.getRightArg(), "zValue");
		assertProof(top.getStringMetricPlanned("optimizer.rewriteProof"),
				"OPTIONAL_WELL_DESIGNED_NORMALIZATION");
	}

	@Test
	void skipsBranchesThatShareIntroducedVariables() {
		StatementPattern base = statementPattern("person", "type", "type");
		StatementPattern zBranch = statementPattern("person", "zProp", "shared");
		StatementPattern aBranch = statementPattern("shared", "aProp", "aValue");
		QueryRoot root = new QueryRoot(new LeftJoin(new LeftJoin(base, zBranch), aBranch));

		optimize(root);

		LeftJoin top = assertInstanceOf(LeftJoin.class, root.getArg(), () -> root.toString());
		LeftJoin inner = assertInstanceOf(LeftJoin.class, top.getLeftArg(), () -> root.toString());
		assertObjectVar(inner.getRightArg(), "shared");
		assertObjectVar(top.getRightArg(), "aValue");
		assertNull(top.getStringMetricPlanned("optimizer.rewriteProof"));
	}

	@Test
	void skipsConditionedLeftJoin() {
		StatementPattern base = statementPattern("person", "type", "type");
		StatementPattern zBranch = statementPattern("person", "zProp", "zValue");
		StatementPattern aBranch = statementPattern("person", "aProp", "aValue");
		Compare condition = new Compare(new Var("aValue"), new Var("zValue"), Compare.CompareOp.EQ);
		QueryRoot root = new QueryRoot(new LeftJoin(new LeftJoin(base, zBranch), aBranch, condition));

		optimize(root);

		LeftJoin top = assertInstanceOf(LeftJoin.class, root.getArg(), () -> root.toString());
		LeftJoin inner = assertInstanceOf(LeftJoin.class, top.getLeftArg(), () -> root.toString());
		assertObjectVar(inner.getRightArg(), "zValue");
		assertObjectVar(top.getRightArg(), "aValue");
		assertNull(top.getStringMetricPlanned("optimizer.rewriteProof"));
	}

	@Test
	void skipsServiceBranches() {
		StatementPattern base = statementPattern("person", "type", "type");
		StatementPattern zBranch = statementPattern("person", "zProp", "zValue");
		Service service = new Service(Var.of("serviceRef", VF.createIRI("urn:service")),
				statementPattern("person", "aProp", "aValue"),
				"SERVICE <urn:service> { ?person <urn:aProp> ?aValue }", Map.of(), null, false);
		QueryRoot root = new QueryRoot(new LeftJoin(new LeftJoin(base, zBranch), service));

		optimize(root);

		LeftJoin top = assertInstanceOf(LeftJoin.class, root.getArg(), () -> root.toString());
		assertInstanceOf(Service.class, top.getRightArg(), () -> root.toString());
		assertNull(top.getStringMetricPlanned("optimizer.rewriteProof"));
	}

	@Test
	void skipsExtensionBranches() {
		StatementPattern base = statementPattern("person", "type", "type");
		StatementPattern zBranch = statementPattern("person", "zProp", "zValue");
		Extension extension = new Extension(statementPattern("person", "aProp", "rawA"),
				new ExtensionElem(new Var("zValue"), "aValue"));
		QueryRoot root = new QueryRoot(new LeftJoin(new LeftJoin(base, zBranch), extension));

		optimize(root);

		LeftJoin top = assertInstanceOf(LeftJoin.class, root.getArg(), () -> root.toString());
		assertInstanceOf(Extension.class, top.getRightArg(), () -> root.toString());
		assertNull(top.getStringMetricPlanned("optimizer.rewriteProof"));
	}

	private static void optimize(TupleExpr tupleExpr) {
		new LmdbOptionalNormalFormOptimizer(new EvaluationStatistics()).optimize(tupleExpr, null,
				EmptyBindingSet.getInstance());
	}

	private static void assertObjectVar(TupleExpr tupleExpr, String expectedName) {
		StatementPattern pattern = assertInstanceOf(StatementPattern.class, tupleExpr, () -> tupleExpr.toString());
		assertEquals(expectedName, pattern.getObjectVar().getName(), () -> tupleExpr.toString());
	}

	private static void assertProof(String metric, String kind) {
		assertTrue(metric != null && metric.contains("proofKind=" + kind), () -> String.valueOf(metric));
		assertTrue(metric.contains("proofScope=LOGICAL_BAG_EQUIVALENT"), () -> metric);
		assertTrue(metric.contains("rule=27"), () -> metric);
		assertTrue(metric.contains("preservedVisibleVars=true"), () -> metric);
		assertTrue(metric.contains("preservedMultiplicity=true"), () -> metric);
		assertTrue(metric.contains("preservedOrder=true"), () -> metric);
		assertTrue(metric.contains("preservedErrors=true"), () -> metric);
		assertTrue(metric.contains("preservedGraphScope=true"), () -> metric);
	}

	private static StatementPattern statementPattern(String subjectName, String predicateName, String objectName) {
		return new StatementPattern(new Var(subjectName), new Var(predicateName, VF.createIRI("urn:" + predicateName)),
				new Var(objectName));
	}
}
